 1	import type { FC } from 'react';
 2	import { useWatch } from 'react-hook-form';
 3	
 4	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 8	import { NetworkMapFieldId } from '../network-map/constants';
 9	
10	const NetworkMapReviewTable: FC = () => {
11	  const { t } = useForkliftTranslation();
12	  const { control } = useCreatePlanFormContext();
13	  const networkMap = useWatch({
14	    control,
15	    name: NetworkMapFieldId.NetworkMap,
16	  });
17	
18	  if (!networkMap) {
19	    return null;
20	  }
21	
22	  return (
23	    <Table aria-label="Network map review table" variant={TableVariant.compact}>
24	      <Thead>
25	        <Tr>
26	          <Th width={50}>{t('Source network')}</Th>
27	          <Th width={50}>{t('Target network')}</Th>
28	        </Tr>
29	      </Thead>
30	
31	      <Tbody>
32	        {networkMap.map((mapping) => {
33	          // Only render rows that have both source and target network names
34	          if (
35	            mapping[NetworkMapFieldId.SourceNetwork].name &&
36	            mapping[NetworkMapFieldId.TargetNetwork].name
37	          ) {
38	            return (
39	              <Tr key={mapping[NetworkMapFieldId.SourceNetwork].name}>
40	                <Td dataLabel={NetworkMapFieldId.SourceNetwork}>
41	                  {mapping[NetworkMapFieldId.SourceNetwork].name}
42	                </Td>
43	                <Td dataLabel={NetworkMapFieldId.TargetNetwork}>
44	                  {mapping[NetworkMapFieldId.TargetNetwork].name}
45	                </Td>
46	              </Tr>
47	            );
48	          }
49	
50	          return null;
51	        })}
52	      </Tbody>
53	    </Table>
54	  );
55	};
56	
57	export default NetworkMapReviewTable;

